+    /// Total events processed.
+    pub event_count: u64,
+    /// Current regime.
+    pub regime: Regime,
+    /// Current event rate (events/sec).
+    pub event_rate: f64,
+    /// Whether there's a pending resize.
+    pub has_pending: bool,
+    /// Last applied size.
+    pub last_applied: (u16, u16),
+}
